const menuLinks=document.querySelectorAll('nav ul li a');const checkbox=document.getElementById('menu-toggle');menuLinks.forEach(link=>{link.addEventListener('click',()=>{checkbox.checked=!1})});document.addEventListener('keydown',(event)=>{if(event.key==='Escape'){const checkbox=document.getElementById('menu-toggle');if(checkbox.checked){checkbox.checked=!1}}});